import{_ as s,o as e,c as i,ag as n}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"Arrays & Slices","description":"","frontmatter":{},"headers":[],"relativePath":"archive/extra/archive/Baseline/13_arrays.md","filePath":"archive/extra/archive/Baseline/13_arrays.md"}'),t={name:"archive/extra/archive/Baseline/13_arrays.md"};function l(r,a,p,o,c,d){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="arrays-slices" tabindex="-1">Arrays &amp; Slices <a class="header-anchor" href="#arrays-slices" aria-label="Permalink to &quot;Arrays &amp; Slices&quot;">​</a></h1><p><strong>Baseline Feature</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented<br><strong>Test:</strong> <code>00_base_feats/13_arrays.vx</code></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Vex supports fixed-size arrays (on stack) and dynamic views called Slices.</p><h2 id="fixed-size-arrays" tabindex="-1">Fixed-Size Arrays <a class="header-anchor" href="#fixed-size-arrays" aria-label="Permalink to &quot;Fixed-Size Arrays&quot;">​</a></h2><p>Arrays have a statically known length. Their size is part of their type <code>[T; N]</code>.</p><h3 id="literals" tabindex="-1">literals <a class="header-anchor" href="#literals" aria-label="Permalink to &quot;literals&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let nums = [1, 2, 3, 4, 5]; // Inferred as [i32; 5]</span></span>
<span class="line"><span>let zeros = [0; 10];        // Repeat syntax: 10 zeros</span></span></code></pre></div><h3 id="accessing-elements" tabindex="-1">Accessing Elements <a class="header-anchor" href="#accessing-elements" aria-label="Permalink to &quot;Accessing Elements&quot;">​</a></h3><p>Zero-based indexing. Bounds checked at runtime (panics if out of bounds).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let first = nums[0];</span></span>
<span class="line"><span>let last = nums[4];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// nums[10]</span><span> // Panic: index out of bounds</span></span></code></pre></div><h3 id="mutability" tabindex="-1">Mutability <a class="header-anchor" href="#mutability" aria-label="Permalink to &quot;Mutability&quot;">​</a></h3><p>To modify an array, it must be declared mutable.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! buffer = [0; 64];</span></span>
<span class="line"><span>buffer[0] = 255;</span></span></code></pre></div><h2 id="slices" tabindex="-1">Slices <a class="header-anchor" href="#slices" aria-label="Permalink to &quot;Slices&quot;">​</a></h2><p>A <strong>Slice</strong> is a view into an array or vector. It consists of a pointer and a length. It does not own the data.</p><p><strong>Type:</strong> <code>[T]</code> (usually seen as reference <code>&amp;[T]</code>)</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let arr = [10, 20, 30, 40, 50];</span></span>
<span class="line"><span>let view = arr[1..4]; // Slice containing [20, 30, 40]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(view[0]); // 20</span></span>
<span class="line"><span>(view.()); // 3</span></span></code></pre></div><h2 id="dynamic-arrays-vec-t" tabindex="-1">Dynamic Arrays (<code>Vec&lt;T&gt;</code>) <a class="header-anchor" href="#dynamic-arrays-vec-t" aria-label="Permalink to &quot;Dynamic Arrays (\`Vec&lt;T&gt;\`)&quot;">​</a></h2><p>For growable lists, use the Standard Library&#39;s <code>Vec&lt;T&gt;</code>.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>let! list = Vec.new&lt;i32&gt;();</span></span>
<span class="line"><span>list.(10);</span></span>
<span class="line"><span>list.(20);</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Array literals <code>[1, 2]</code> create fixed-size arrays by default. To create a Vec, usually <code>Vec.new()</code> or conversion is used.</p></div><h2 id="implementation-details" tabindex="-1">Implementation Details <a class="header-anchor" href="#implementation-details" aria-label="Permalink to &quot;Implementation Details&quot;">​</a></h2><h3 id="ast" tabindex="-1">AST <a class="header-anchor" href="#ast" aria-label="Permalink to &quot;AST&quot;">​</a></h3><p><code>vex-ast/src/expressions.rs</code>:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Expression</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Array</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Vec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Expression</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// [a, b, c]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Expression</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ArrayRepeat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(value, count)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// [v; n]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Expression</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Index</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { object, index }         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// a[i]</span></span></code></pre></div><h3 id="memory" tabindex="-1">Memory <a class="header-anchor" href="#memory" aria-label="Permalink to &quot;Memory&quot;">​</a></h3><ul><li><strong>Array:</strong> Contiguous block on stack (or heap if very large/global).</li><li><strong>Slice:</strong> Two words (ptr, len).</li></ul>`,28)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
